import{_ as t,o as a,c as i,ae as r}from"./chunks/framework.B6gjLfeO.js";const u=JSON.parse('{"title":"iOS 17 Privacy Overview","description":"","frontmatter":{"title":"iOS 17 Privacy Overview","slug":"ios-17-privacy-overview"},"headers":[],"relativePath":"developer-hub/ios-17-privacy-overview.md","filePath":"developer-hub/ios-17-privacy-overview.md"}'),n={name:"developer-hub/ios-17-privacy-overview.md"};function o(s,e,d,l,c,h){return a(),i("div",null,[...e[0]||(e[0]=[r('<h2 id="ios-17-privacy-glossary" tabindex="-1">iOS 17 Privacy Glossary <a class="header-anchor" href="#ios-17-privacy-glossary" aria-label="Permalink to &quot;iOS 17 Privacy Glossary&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Term</th><th>Definition</th></tr></thead><tbody><tr><td><strong>Privacy Manifests</strong></td><td>Standardized files that outline the privacy practices of an app or third-party framework (SDK).</td></tr><tr><td><strong>Privacy Report</strong></td><td>An auto-generated reference doc, based on the details contained in all relevant Privacy Manifest files, designed to make it easier to fill out the Privacy Nutrition Label questionnaire during App Store submission.</td></tr><tr><td><strong>SDK Signing</strong></td><td>A way for app developers to be confident that the third-party SDKs they use (such as Branch) are the original, validated versions and have not been tampered with.</td></tr><tr><td><strong>Privacy-impacting SDKs</strong></td><td>A list of SDKs that Apple judges to have particularly high impact on user privacy. Any SDK on this list will be <em>required</em> to include a Privacy Manifest file, and be signed by the original developer (these steps are also recommended but not required for SDKs that are not on the list).</td></tr><tr><td><strong>Required Reason APIs</strong></td><td>A limited selection of iOS functionality that could potentially be used for fingerprinting, for which an &quot;allowed reason&quot; for usage must be declared in the Privacy Manifest file. (Note that &quot;API&quot; in this context means things like accessing disk space, not service APIs the way we typically think of them in the world of mobile marketing)</td></tr><tr><td><strong>Tracking Domains</strong></td><td>Internet domains that an app or SDK connects to that engage in &quot;tracking.&quot; These must be declared in the Privacy Manifest file, and network requests to these domains will fail until the user gives ATT consent.</td></tr><tr><td><strong>Domain Profiler in Instruments</strong></td><td>Tooling in Xcode that developers can use to compare an app&#39;s network requests against a list of internet domains the OS believes to be capable of &quot;profiling&quot; across multiple apps and websites.</td></tr><tr><td><strong>Link Tracking Protection and Safari Private Browsing Improvements</strong></td><td>New functionality in Messages, Mail, and Safari Private Browsing to strip URL query parameters used to track users across websites, and block various other forms of cross-site tracking.</td></tr><tr><td><strong>SKAdNetwork 5.0</strong></td><td>The new version will support re-engagement attribution (app opens).</td></tr></tbody></table><h2 id="timelines" tabindex="-1">Timelines <a class="header-anchor" href="#timelines" aria-label="Permalink to &quot;Timelines&quot;">​</a></h2><h2 id="branch-support" tabindex="-1">Branch Support <a class="header-anchor" href="#branch-support" aria-label="Permalink to &quot;Branch Support&quot;">​</a></h2><h3 id="privacy-manifest-file-creation" tabindex="-1">Privacy Manifest File Creation <a class="header-anchor" href="#privacy-manifest-file-creation" aria-label="Permalink to &quot;Privacy Manifest File Creation&quot;">​</a></h3><p>Branch now supports Privacy Manifest files, an essential addition for App Store submissions.</p><p>Branch&#39;s own iOS SDK Privacy Manifest <a href="https://github.com/BranchMetrics/ios-branch-deep-linking-attribution/blob/master/Sources/Resources/PrivacyInfo.xcprivacy" target="_blank" rel="noreferrer">file</a> includes:</p><ul><li>The declaration of <code>NSPrivacyTrackingDomains</code> to meet Apple&#39;s requirements.</li><li>A list of <code>NSPrivacyAccessedAPITypes</code> with valid use reasons.</li><li>Details on the data that the Branch iOS SDK collects, referred to as <code>NSPrivacyCollectedDataTypes</code>.</li></ul><p><strong>Note</strong>: If you are collecting and passing info to the Branch iOS SDK, you need to declare that in your own Privacy Manifest file in your app, since Branch cannot see the data being passed. This includes things like hashed identifiers and other sensitive information.</p><h3 id="sdk-and-backend-updates" tabindex="-1">SDK and Backend Updates <a class="header-anchor" href="#sdk-and-backend-updates" aria-label="Permalink to &quot;SDK and Backend Updates&quot;">​</a></h3><p>Branch has updated the iOS SDK as well as our backend to adhere to iOS 17 privacy policies.</p><p>Updates include:</p><ul><li><p>Changes to support compliance and flexibility for tracking and measurement.</p></li><li><p>The creation of dedicated domains for network requests:</p><ul><li>A dedicated tracking domain (api-safetrack.branch.io), designed for ads measurement, is declared in the privacy manifest. Branch will only use this domain when users have opted in to App Tracking Transparency (ATT).</li><li>A dedicated non-tracking domain (api3.branch.io) used by Branch for API requests related to non-ads measurement and deep linking. Notably, there’s no requirement to declare this domain in the privacy manifest, since traffic through it doesn’t contribute to “tracking” (ads measurement).</li></ul></li></ul><h3 id="sdk-signing" tabindex="-1">SDK Signing <a class="header-anchor" href="#sdk-signing" aria-label="Permalink to &quot;SDK Signing&quot;">​</a></h3><p>Starting with iOS 17, Branch will sign the iOS SDK to support user privacy. This aligns with Apple&#39;s requirements for Spring 2024 compliance.</p><h2 id="additional-resources" tabindex="-1">Additional Resources <a class="header-anchor" href="#additional-resources" aria-label="Permalink to &quot;Additional Resources&quot;">​</a></h2><ul><li>[Dev Docs] <a href="./ios-sdk-overview.html">iOS SDK Overview</a></li><li>[Changelog] <a href="./ios-17-privacy-changes.html">iOS 17 Privacy Changes</a></li><li>[Blog] <a href="https://www.branch.io/resources/blog/the-dark-horse-of-wwdc-2023-privacy-policies-finally-get-real/" target="_blank" rel="noreferrer">The Dark Horse of WWDC 2023: Privacy Policies Finally Get Real</a></li><li>[Blog] <a href="https://www.branch.io/resources/blog/navigating-ios-17s-privacy-landscape-the-road-ahead-for-app-developers-and-advertisers/" target="_blank" rel="noreferrer">Navigating iOS 17’s Privacy Landscape: The Road Ahead for App Developers and Advertisers</a></li></ul>',17)])])}const g=t(n,[["render",o]]);export{u as __pageData,g as default};
